        $$->start = $2 & 0xFFFF;;
        $$->end = $2 >> 16;;
        $$->greedy = false;
      }
    | single
      {
        $$ = $1;
      }
    | _WORD_BOUNDARY_
      {
        $$ = yr_re_node_create(RE_NODE_WORD_BOUNDARY);

