        fail_if($$ == NULL, ERROR_INSUFFICIENT_MEMORY);

        $$->value = $1;
        $$->mask = 0xFF;
      }
    | _WORD_CHAR_
      {
        $$ = yr_re_node_create(RE_NODE_WORD_CHAR);

