#include <stdio.h>
#include <string.h>

#define CHAR_IN_CLASS(cls, chr)  \
  ((cls)[(chr) / 8] & 1 << ((chr) % 8))

typedef struct {
    unsigned char bitmap[32];
    int negated;
} RE_CLASS;

int _yr_re_is_char_in_class(
    RE_CLASS* re_class,
    unsigned char chr,
    int case_insensitive)
{
  int result = CHAR_IN_CLASS(re_class->bitmap, chr);

  if (case_insensitive)
    result |= CHAR_IN_CLASS(re_class->bitmap, chr); // simplified, no altercase

  if (re_class->negated)
    result = !result;

  return result;
}

int main() {
    RE_CLASS re_class;
    memset(&re_class.bitmap, 0, 32);
    re_class.negated = 1;

    // Set bit for 'x' (120)
    re_class.bitmap[120 / 8] |= 1 << (120 % 8);
    printf("bitmap[15] = 0x%02x\n", re_class.bitmap[15]);

    // Test with character 224 (0xE0)
